router4.post(
  "/generate-word-from-text",
  authMiddleware,
  requireRole(["admin"]),
  async (req, res) => {
    try {
      const { text: text2, variables } = req.body;
      if (!text2 || !variables || !Array.isArray(variables)) {
        return res.status(400).json({
          success: false,
          message: "\u0645\u062A\u0646 \u06CC\u0627 \u0645\u062A\u063A\u06CC\u0631\u0647\u0627 \u0627\u0631\u0633\u0627\u0644 \u0646\u0634\u062F\u0647 \u0627\u0633\u062A"
        });
      }
      console.log(`\u{1F4C4} Generating Word document with ${variables.length} variables`);
      let processedText = text2;
      for (const variable of variables) {
        if (variable.original && variable.name) {
          const placeholder = `{{${variable.name}}}`;
          const escapedOriginal = variable.original.replace(/[.*+?^${}()|[\]\\]/g, "\\$&");
          processedText = processedText.replace(new RegExp(escapedOriginal, "g"), placeholder);
        }
      }
      const Document = __require("docx").Document;
      const Paragraph = __require("docx").Paragraph;
      const TextRun = __require("docx").TextRun;
      const Packer = __require("docx").Packer;
      const paragraphs = processedText.split("\n").map(
        (para) => new Paragraph({
          children: [new TextRun({ text: para, rightToLeft: true })]
        })
      );
      const doc = new Document({
        sections: [{
          properties: {},
          children: paragraphs
        }]
      });
      const buffer = await Packer.toBuffer(doc);
      res.setHeader("Content-Type", "application/vnd.openxmlformats-officedocument.wordprocessingml.document");
      res.setHeader("Content-Disposition", `attachment; filename="processed_text_${Date.now()}.docx"`);
      res.send(buffer);
      console.log(`\u2705 Word document generated successfully`);
    } catch (error) {
      console.error("\u274C Word generation error:", error);
      res.status(500).json({
        success: false,
        message: error instanceof Error ? error.message : "\u062E\u0637\u0627 \u062F\u0631 \u062A\u0648\u0644\u06CC\u062F \u0641\u0627\u06CC\u0644 Word"
      });
    }
  }
);
