import { Router as Router8 } from "express";

// server/services/bale-chat.service.ts
init_storage();
init_socket_manager();
var BaleChatService = class {
  /**
   * Process Bale webhook
   */
  async processWebhook(webhookData) {
    console.log("\u{1F4E8} Bale webhook received:", JSON.stringify(webhookData, null, 2));
    await baleBotService.handleWebhook(webhookData);
  }
  /**
   * Get conversations based on user role and department
   */
  async getConversations(userId, userRole) {
    let conversations2 = [];
    if (userRole === "admin") {
      const departments2 = await storage2.getDepartments();
      for (const dept of departments2) {
        const deptConversations = await storage2.getBaleConversationsByDepartment(dept.id);
        conversations2.push(...deptConversations);
      }
    } else if (userRole === "employee") {
      const user = await storage2.getUser(userId);
      if (user?.department) {
        const dept = await storage2.getDepartments();
        const userDept = dept.find((d) => d.slug === user.department || d.name === user.department);
        if (userDept) {
          conversations2 = await storage2.getBaleConversationsByDepartment(userDept.id);
        }
      }
    } else {
      throw new Error("\u062F\u0633\u062A\u0631\u0633\u06CC \u0645\u062D\u062F\u0648\u062F");
    }
    const conversationsWithMessages = await Promise.all(
      conversations2.map(async (conv) => {
        const messages2 = await storage2.getBaleMessagesByConversation(conv.id);
        const lastMessage = messages2[messages2.length - 1];
        return {
          ...conv,
          lastMessage,
          unreadCount: messages2.filter((m) => !m.isDelivered && m.senderType === "customer").length
        };
      })
    );
    return conversationsWithMessages;
  }
  /**
   * Create new Bale conversation
   */
  async createConversation(conversationData) {
    if (!conversationData.departmentId || !conversationData.customerName) {
      throw new Error("\u0627\u0637\u0644\u0627\u0639\u0627\u062A \u0646\u0627\u0642\u0635 \u0627\u0633\u062A");
    }
    const data = {
      ...conversationData,
      title: conversationData.title || `\u06AF\u0641\u062A\u06AF\u0648 \u0628\u0627 ${conversationData.customerName}`,
      status: conversationData.status || "active"
    };
    return await storage2.createBaleConversation(data);
  }
  /**
   * Get single conversation by ID
   */
  async getConversation(conversationId) {
    return await storage2.getBaleConversation(conversationId);
  }
  /**
   * Get messages for a conversation
   */
  async getConversationMessages(conversationId) {
    const conversation = await this.getConversation(conversationId);
    if (!conversation) {
      throw new Error("\u0645\u06A9\u0627\u0644\u0645\u0647 \u06CC\u0627\u0641\u062A \u0646\u0634\u062F");
    }
    const messages2 = await storage2.getBaleMessagesByConversation(conversationId);
    const undeliveredMessages = messages2.filter((m) => !m.isDelivered && m.platform === "bale");
    for (const msg of undeliveredMessages) {
      await storage2.updateBaleMessageDelivery(msg.id, true);
    }
    return messages2;
  }
  /**
   * Send message in conversation
   */
  async sendMessage(conversationId, messageData, senderInfo) {
    if (!messageData.content || !messageData.content.trim()) {
      throw new Error("\u0645\u062A\u0646 \u067E\u06CC\u0627\u0645 \u0627\u0644\u0632\u0627\u0645\u06CC \u0627\u0633\u062A");
    }
    const conversation = await this.getConversation(conversationId);
    if (!conversation) {
      throw new Error("\u0645\u06A9\u0627\u0644\u0645\u0647 \u06CC\u0627\u0641\u062A \u0646\u0634\u062F");
    }
    const message = await storage2.createBaleMessage({
      conversationId,
      content: messageData.content.trim(),
      messageType: messageData.messageType || "text",
      platform: messageData.platform || "web",
      senderType: senderInfo.role === "customer" ? "customer" : "staff",
      baleUserId: messageData.baleUserId || null,
      isDelivered: messageData.isDelivered || false
    });
    socketManager.sendToConversation(conversationId, "new_message", {
      message,
      conversation
    });
    if (senderInfo.role !== "customer" && conversation.customerPhone) {
      try {
        await baleBotService.notifyDepartmentStaff(
          conversation.departmentId,
          `\u{1F4AC} \u067E\u06CC\u0627\u0645 \u062C\u062F\u06CC\u062F \u0627\u0632 ${senderInfo.username} \u0628\u0631\u0627\u06CC ${conversation.customerName}:

${messageData.content}`
        );
      } catch (notifyError) {
        console.error("Error notifying department staff:", notifyError);
      }
    }
    return message;
  }
  /**
   * Update conversation status
   */
  async updateConversation(conversationId, updateData) {
    if (updateData.status && !["active", "closed", "archived"].includes(updateData.status)) {
      throw new Error("\u0648\u0636\u0639\u06CC\u062A \u0646\u0627\u0645\u0639\u062A\u0628\u0631 \u0627\u0633\u062A");
    }
    const conversation = await storage2.updateBaleConversation(conversationId, updateData);
    if (!conversation) {
      throw new Error("\u0645\u06A9\u0627\u0644\u0645\u0647 \u06CC\u0627\u0641\u062A \u0646\u0634\u062F");
    }
    return conversation;
  }
  /**
   * Authenticate staff via Bale
   */
  async authenticateStaff(authData) {
    const { chatId, phoneNumber } = authData;
    if (!chatId || !phoneNumber) {
      throw new Error("\u0627\u0637\u0644\u0627\u0639\u0627\u062A \u0646\u0627\u0642\u0635 \u0627\u0633\u062A");
    }
    const authorizedPhones2 = await storage2.getAuthorizedPhoneByNumber(phoneNumber);
    const authorizedPhone = Array.isArray(authorizedPhones2) ? authorizedPhones2[0] : authorizedPhones2;
    if (!authorizedPhone || !authorizedPhone.isActive) {
      throw new Error("\u0634\u0645\u0627\u0631\u0647 \u062A\u0644\u0641\u0646 \u0645\u062C\u0627\u0632 \u0646\u06CC\u0633\u062A");
    }
    let baleUser = await storage2.getBaleUserByChatId(chatId);
    if (baleUser) {
      await storage2.updateBaleUser(baleUser.id, {
        phoneNumber,
        departmentId: authorizedPhone.departmentId,
        isAuthenticated: true
      });
    } else {
      baleUser = await storage2.createBaleUser({
        baleUserId: chatId,
        baleChatId: chatId,
        phoneNumber,
        departmentId: authorizedPhone.departmentId,
        isAuthenticated: true
      });
    }
    const department = await storage2.getDepartment(authorizedPhone.departmentId);
    return {
      success: true,
      message: "\u0627\u062D\u0631\u0627\u0632 \u0647\u0648\u06CC\u062A \u0645\u0648\u0641\u0642",
      department,
      baleUser
    };
  }
  /**
   * Get departments list
   */
  async getDepartments() {
    return await storage2.getDepartments();
  }
  /**
   * Validate user access to conversation
   */
  async validateConversationAccess(userId, userRole, conversationId) {
    const conversation = await this.getConversation(conversationId);
    if (!conversation) {
      return false;
    }
    if (userRole === "admin") {
      return true;
    }
    if (userRole === "employee") {
      const user = await storage2.getUser(userId);
      if (user?.department) {
        const departments2 = await storage2.getDepartments();
        const userDept = departments2.find((d) => d.slug === user.department || d.name === user.department);
        return userDept?.id === conversation.departmentId;
      }
    }
    return false;
  }
  /**
   * Get conversation statistics
   */
  async getConversationStats(departmentId) {
    const departments2 = departmentId ? [{ id: departmentId }] : await storage2.getDepartments();
    let totalConversations = 0;
    let activeConversations = 0;
    let totalMessages = 0;
    for (const dept of departments2) {
      const conversations2 = await storage2.getBaleConversationsByDepartment(dept.id);
      totalConversations += conversations2.length;
      activeConversations += conversations2.filter((c) => c.status === "active").length;
      for (const conv of conversations2) {
        const messages2 = await storage2.getBaleMessagesByConversation(conv.id);
        totalMessages += messages2.length;
      }
    }
    return {
      totalConversations,
      activeConversations,
      closedConversations: totalConversations - activeConversations,
      totalMessages,
      averageMessagesPerConversation: totalConversations > 0 ? Math.round(totalMessages / totalConversations) : 0
    };
  }
};
