companiesRoutes.post("/", authMiddleware, requireRole(["admin", "customer"]), (req, res) => companiesController.createCompany(req, res));
companiesRoutes.patch("/:id", authMiddleware, (req, res) => companiesController.updateCompany(req, res));
companiesRoutes.post("/validate", authMiddleware, requireRole(["admin", "ceo", "employee"]), (req, res) => companiesController.validateCompany(req, res));
companiesRoutes.get("/:id/enrich", authMiddleware, requireRole(["admin", "ceo", "employee"]), (req, res) => companiesController.enrichCompanyData(req, res));
companiesRoutes.get("/:id/ai-analysis", authMiddleware, requireRole(["admin", "ceo", "employee"]), (req, res) => companiesController.getCompanyAIAnalysis(req, res));
companiesRoutes.get("/:id/tax-declaration-status", authMiddleware, (req, res) => companiesController.getTaxDeclarationStatus(req, res));
companiesRoutes.get("/:id/financial-summary", authMiddleware, (req, res) => companiesController.getFinancialSummary(req, res));
companiesRoutes.post("/:id/reprocess-tax-declaration", authMiddleware, requireRole(["admin", "ceo", "employee"]), (req, res) => companiesController.reprocessTaxDeclaration(req, res));
companiesRoutes.get("/:id/financial-trends", authMiddleware, (req, res) => companiesController.getFinancialTrends(req, res));
companiesRoutes.put("/:id/info/:type", authMiddleware, (req, res) => companiesController.updateCompanyInfo(req, res));
var adminCompaniesRoutes = Router9();
adminCompaniesRoutes.delete("/companies/:id", authMiddleware, requireRole(["admin"]), (req, res) => companiesController.deleteCompany(req, res));

