// server/middleware/rate-limiter.ts
var RateLimiter = class {
  /**
   * پاکسازی خودکار ورودی‌های منقضی شده هر 10 دقیقه
   */
  constructor() {
    this.store = {};
    setInterval(() => this.cleanupExpiredEntries(), 6e5);
  }
  /**
   * ایجاد middleware با تنظیمات مشخص
   */
  create(config) {
    const {
      windowMs,
      maxRequests,
      message = "\u062A\u0639\u062F\u0627\u062F \u062F\u0631\u062E\u0648\u0627\u0633\u062A\u200C\u0647\u0627\u06CC \u0634\u0645\u0627 \u0628\u06CC\u0634 \u0627\u0632 \u062D\u062F \u0645\u062C\u0627\u0632 \u0627\u0633\u062A. \u0644\u0637\u0641\u0627\u064B \u0628\u0639\u062F\u0627\u064B \u062A\u0644\u0627\u0634 \u06A9\u0646\u06CC\u062F.",
      skipSuccessfulRequests = false
    } = config;
    return (req, res, next) => {
      const identifier = this.getIdentifier(req);
      const now = Date.now();
      if (!this.store[identifier] || now > this.store[identifier].resetTime) {
        this.store[identifier] = {
          count: 0,
          resetTime: now + windowMs
        };
      }
      const entry = this.store[identifier];
      if (entry.count >= maxRequests) {
        const retryAfter = Math.ceil((entry.resetTime - now) / 1e3);
        res.setHeader("X-RateLimit-Limit", maxRequests.toString());
        res.setHeader("X-RateLimit-Remaining", "0");
        res.setHeader("X-RateLimit-Reset", entry.resetTime.toString());
        res.setHeader("Retry-After", retryAfter.toString());
        console.warn(`\u{1F6AB} Rate limit exceeded for ${identifier}: ${entry.count}/${maxRequests}`);
        return res.status(429).json({
          success: false,
          error: message,
          retryAfter,
          limit: maxRequests,
          windowMs
        });
      }
      entry.count++;
      res.setHeader("X-RateLimit-Limit", maxRequests.toString());
      res.setHeader("X-RateLimit-Remaining", (maxRequests - entry.count).toString());
      res.setHeader("X-RateLimit-Reset", entry.resetTime.toString());
      if (skipSuccessfulRequests) {
        res.on("finish", () => {
          if (res.statusCode < 400) {
            entry.count = Math.max(0, entry.count - 1);
          }
        });
      }
      next();
    };
  }
  /**
   * شناسایی یکتای کاربر
   */
  getIdentifier(req) {
    const authReq = req;
    if (authReq.user?.userId) {
      return `user_${authReq.user.userId}`;
    }
    const ip = req.ip || req.headers["x-forwarded-for"]?.toString().split(",")[0].trim() || req.socket.remoteAddress || "unknown";
    return `ip_${ip}`;
  }
  /**
   * پاکسازی ورودی‌های منقضی شده
   */
  cleanupExpiredEntries() {
    const now = Date.now();
    let removedCount = 0;
    for (const key in this.store) {
      if (this.store[key].resetTime < now) {
        delete this.store[key];
        removedCount++;
      }
    }
    if (removedCount > 0) {
      console.log(`\u{1F5D1}\uFE0F Rate limiter: cleaned ${removedCount} expired entries`);
    }
  }
  /**
   * پاکسازی کامل store
   */
  clearAll() {
    this.store = {};
    console.log("\u{1F5D1}\uFE0F Rate limiter store cleared");
  }
  /**
   * دریافت آمار
   */
  getStats() {
    return {
      totalEntries: Object.keys(this.store).length,
      entries: { ...this.store }
    };
  }
};
