formSubmissionsRoutes.post("/", authMiddleware, (req, res) => documentRequirementsController.createFormSubmission(req, res));
formSubmissionsRoutes.get("/pending", authMiddleware, requireRole(["admin", "ceo", "employee"]), (req, res) => documentRequirementsController.getPendingSubmissions(req, res));
formSubmissionsRoutes.get("/:id", authMiddleware, (req, res) => documentRequirementsController.getFormSubmission(req, res));
formSubmissionsRoutes.patch("/:id", authMiddleware, requireRole(["admin", "employee"]), (req, res) => documentRequirementsController.updateFormSubmission(req, res));
formSubmissionsRoutes.delete("/:id", authMiddleware, requireRole(["admin", "employee"]), (req, res) => documentRequirementsController.deleteFormSubmission(req, res));

