function setupSecurityMiddleware(app2) {
  const envAllowed = process.env.ALLOWED_ORIGINS ? process.env.ALLOWED_ORIGINS.split(",") : [];
  const allowedOrigins = process.env.NODE_ENV === "production" ? ["https://portal.gilanfund.ir", "https://www.portal.gilanfund.ir", "http://localhost:5000", "http://127.0.0.1:5000", process.env.CLIENT_URL, ...envAllowed].filter(Boolean) : ["http://localhost:5000", "http://localhost:3000", "http://127.0.0.1:5000", "*"];
  app2.use(cors({
    origin: function(origin, callback) {
      if (!origin || allowedOrigins.includes("*") || allowedOrigins.includes(origin)) {
        callback(null, true);
      } else {
        callback(new Error("Not allowed by CORS"));
      }
    },
    credentials: true
  }));
  app2.use(
    helmet({
      contentSecurityPolicy: {
        directives: {
          defaultSrc: ["'self'"],
          styleSrc: ["'self'", "'unsafe-inline'"],
          scriptSrc: ["'self'", "'unsafe-inline'", "'unsafe-eval'"],
          // Required for Vite dev mode
          imgSrc: ["'self'", "data:", "blob:", "https:"],
          connectSrc: ["'self'", "ws:", "wss:"]
          // For Socket.io
        }
      },
      crossOriginEmbedderPolicy: false
      // Required for some assets
    })
  );
  app2.use("/api/", apiLimiter);
  app2.use("/api/auth/login", authLimiter);
  app2.use("/api/auth/register", authLimiter);
  app2.use("/api/auth/customer-login", authLimiter);
  app2.use("/api/otp/", otpLimiter);
  app2.use("/api/user/send-phone-otp", otpLimiter);
  app2.use("/api/contract-templates/upload", uploadLimiter);
  console.log("\u2705 Security middleware initialized");
}
function validateEnvironmentVariables() {
  const required = [
    "JWT_SECRET",
    "DATABASE_URL"
  ];
  const missing = [];
  for (const variable of required) {
    if (!process.env[variable]) {
      missing.push(variable);
    }
  }
  if (missing.length > 0) {
    throw new Error(
      `Missing required environment variables: ${missing.join(", ")}
Please create a .env file with the required variables.`
    );
  }
  const jwtSecret = process.env.JWT_SECRET;
  if (jwtSecret && jwtSecret.length < 32) {
    console.warn(
      "\u26A0\uFE0F  WARNING: JWT_SECRET is too short. Please use at least 32 characters for production."
    );
  }
  const nodeEnv = process.env.NODE_ENV || "development";
  if (!["development", "production", "test"].includes(nodeEnv)) {
    console.warn(
      `\u26A0\uFE0F  WARNING: Invalid NODE_ENV value: ${nodeEnv}. Using 'development' as default.`
    );
  }
  console.log("\u2705 Environment variables validated");
}

