      "progress": "\u06AF\u0632\u0627\u0631\u0634 \u067E\u06CC\u0634\u0631\u0641\u062A",
      "final": "\u06AF\u0632\u0627\u0631\u0634 \u0646\u0647\u0627\u06CC\u06CC",
      "risk_assessment": "\u06AF\u0632\u0627\u0631\u0634 \u0627\u0631\u0632\u06CC\u0627\u0628\u06CC \u0631\u06CC\u0633\u06A9"
