      logger.info(`\u{1F504} \u062A\u06A9\u0645\u06CC\u0644 \u0627\u0637\u0644\u0627\u0639\u0627\u062A \u0634\u0631\u06A9\u062A ${company.name} \u0627\u0632 \u0631\u0627\u0633\u0645\u06CC\u0648`, "rasmio-integration");
