// server/routes/client-logs.routes.ts
init_logger();
import { Router as Router25 } from "express";
import { z as z2 } from "zod";
var router11 = Router25();
var clientLogSchema = z2.object({
  level: z2.enum(["debug", "info", "warn", "error"]),
  message: z2.string(),
  stack: z2.string().optional(),
  url: z2.string().optional(),
  userAgent: z2.string().optional(),
  meta: z2.record(z2.any()).optional(),
  timestamp: z2.string().optional()
});
router11.post("/", (req, res) => {
  const result = clientLogSchema.safeParse(req.body);
  if (!result.success) {
    logger.warn("Invalid client log format", "client-logger", { errors: result.error.errors });
    return res.status(400).json({ success: false, message: "Invalid log format" });
  }
  const { level, message, stack, url, userAgent, meta } = result.data;
  const source = "client";
  const logData = {
    url,
    userAgent,
    ...meta,
    clientStack: stack
  };
  if (level === "error") {
    logger.error(message, source, stack ? new Error(stack) : void 0, void 0, logData);
  } else if (level === "warn") {
    logger.warn(message, source, logData);
  } else if (level === "info") {
    logger.info(message, source, logData);
  } else {
    logger.debug(message, source, logData);
  }
  res.json({ success: true });
});
var client_logs_routes_default = router11;

