// server/errors/AppError.ts
var AppError = class _AppError extends Error {
  constructor(message, statusCode = 500, isOperational = true, details) {
    super(message);
    this.statusCode = statusCode;
    this.isOperational = isOperational;
    this.details = details;
    Error.captureStackTrace(this, this.constructor);
    Object.setPrototypeOf(this, _AppError.prototype);
  }
  toJSON() {
    return {
      message: this.message,
      statusCode: this.statusCode,
      ...this.details && { details: this.details }
    };
  }
};

// server/middleware/errorHandler.ts
init_logger();
import { ZodError } from "zod";
function normalizeError(error) {
  if (error instanceof AppError) {
    return error;
  }
  if (error instanceof ZodError) {
    const details = error.errors.map((err) => ({
      field: err.path.join("."),
      message: err.message
    }));
    return new AppError(
      "\u0627\u0637\u0644\u0627\u0639\u0627\u062A \u0627\u0631\u0633\u0627\u0644\u06CC \u0646\u0627\u0645\u0639\u062A\u0628\u0631 \u0627\u0633\u062A",
      422,
      true,
      details
    );
  }
  if (error.name === "JsonWebTokenError") {
    return new AppError("\u062A\u0648\u06A9\u0646 \u0646\u0627\u0645\u0639\u062A\u0628\u0631 \u0627\u0633\u062A", 401, true);
  }
  if (error.name === "TokenExpiredError") {
    return new AppError("\u062A\u0648\u06A9\u0646 \u0645\u0646\u0642\u0636\u06CC \u0634\u062F\u0647 \u0627\u0633\u062A", 401, true);
  }
  if (error.message.includes("UNIQUE constraint")) {
    const match = error.message.match(/UNIQUE constraint failed: (\w+)\.(\w+)/);
    const field = match ? match[2] : "field";
    return new AppError(
      `\u0627\u06CC\u0646 ${field} \u0642\u0628\u0644\u0627\u064B \u0627\u0633\u062A\u0641\u0627\u062F\u0647 \u0634\u062F\u0647 \u0627\u0633\u062A`,
      409,
      true,
      { field }
    );
  }
  if (error.message.includes("FOREIGN KEY constraint")) {
    return new AppError(
      "\u0646\u0645\u06CC\u200C\u062A\u0648\u0627\u0646 \u0627\u06CC\u0646 \u0631\u06A9\u0648\u0631\u062F \u0631\u0627 \u062D\u0630\u0641 \u06A9\u0631\u062F \u0632\u06CC\u0631\u0627 \u0648\u0627\u0628\u0633\u062A\u06AF\u06CC \u062F\u0627\u0631\u062F",
      409,
      true
    );
  }
  if (error.message.includes("SQLITE_BUSY")) {
    return new AppError(
      "\u067E\u0627\u06CC\u06AF\u0627\u0647 \u062F\u0627\u062F\u0647 \u0645\u0634\u063A\u0648\u0644 \u0627\u0633\u062A\u060C \u0644\u0637\u0641\u0627\u064B \u062F\u0648\u0628\u0627\u0631\u0647 \u062A\u0644\u0627\u0634 \u06A9\u0646\u06CC\u062F",
      503,
      true
    );
  }
  return new AppError(
    "\u062E\u0637\u0627\u06CC \u062F\u0627\u062E\u0644\u06CC \u0633\u0631\u0648\u0631",
    500,
    false,
    process.env.NODE_ENV === "development" ? error.message : void 0
  );
}
var globalErrorHandler = (error, req, res, next) => {
  const appError = normalizeError(error);
  const context = storage.getStore();
  const requestId = context?.requestId || req.context?.requestId;
  if (appError.isOperational) {
    logger.warn(
      appError.message,
      "error-handler",
      {
        statusCode: appError.statusCode,
        path: req.path,
        method: req.method,
        userId: req.user?.userId,
        details: appError.details,
        requestId
      }
    );
  } else {
    logger.error(
      appError.message,
      "error-handler",
      error,
      void 0,
      // category
      {
        statusCode: appError.statusCode,
        path: req.path,
        method: req.method,
        userId: req.user?.userId,
        stack: error.stack,
        requestId
      }
    );
  }
  const response = {
    success: false,
    message: appError.message,
    statusCode: appError.statusCode,
    requestId
    // Include requestId in response
  };
  if (appError.details && (process.env.NODE_ENV === "development" || appError.isOperational)) {
    response.details = appError.details;
  }
  if (process.env.NODE_ENV === "development") {
    response.stack = error.stack;
  }
  res.status(appError.statusCode).json(response);
};
var notFoundHandler = (req, res, next) => {
  const error = new AppError(
    `\u0645\u0633\u06CC\u0631 ${req.originalUrl} \u06CC\u0627\u0641\u062A \u0646\u0634\u062F`,
    404,
    true,
    {
      method: req.method,
      path: req.originalUrl
    }
  );
  next(error);
};
var setupUnhandledRejectionHandler = () => {
  process.on("unhandledRejection", (reason) => {
    logger.error(
      "Unhandled Promise Rejection",
      "process",
      reason instanceof Error ? reason : new Error(String(reason))
    );
    if (process.env.NODE_ENV === "production") {
      console.error("Unhandled Rejection - shutting down...");
      process.exit(1);
    }
  });
};
var setupUncaughtExceptionHandler = () => {
  process.on("uncaughtException", (error) => {
    logger.error("Uncaught Exception", "process", error);
    console.error("Uncaught Exception - shutting down...");
    process.exit(1);
  });
};

// server/services/temp-file-cleanup.service.ts
init_logger();
import * as fs17 from "fs/promises";
import * as path16 from "path";
var TempFileCleanupService = class {
  constructor() {
    this.isRunning = false;
    this.TEMP_DIR = path16.join(process.cwd(), "temp");
    this.MAX_AGE_MS = 24 * 60 * 60 * 1e3;
    // 24 hours
    this.CLEANUP_INTERVAL_MS = 60 * 60 * 1e3;
    // 1 hour
    this.intervalId = null;
  }
  /**
   * شروع سرویس پاکسازی خودکار
   */
  start() {
    if (this.isRunning) {
      logger.warn("Temp file cleanup service is already running", "temp-cleanup");
      return;
    }
    logger.info("Starting temp file cleanup service", "temp-cleanup");
    this.isRunning = true;
    this.cleanup().catch((error) => {
      logger.error("Initial cleanup failed", "temp-cleanup", error);
    });
    this.intervalId = setInterval(() => {
      this.cleanup().catch((error) => {
        logger.error("Scheduled cleanup failed", "temp-cleanup", error);
      });
    }, this.CLEANUP_INTERVAL_MS);
    logger.info(`Cleanup scheduled every ${this.CLEANUP_INTERVAL_MS / 1e3 / 60} minutes`, "temp-cleanup");
  }
  /**
   * توقف سرویس پاکسازی
   */
  stop() {
    if (!this.isRunning) {
      return;
    }
    logger.info("Stopping temp file cleanup service", "temp-cleanup");
    if (this.intervalId) {
      clearInterval(this.intervalId);
      this.intervalId = null;
    }
    this.isRunning = false;
  }
  /**
   * پاکسازی فایل‌های موقت قدیمی
   */
  async cleanup() {
    try {
      logger.info("Starting temp file cleanup", "temp-cleanup");
      try {
        await fs17.access(this.TEMP_DIR);
      } catch {
        logger.debug("Temp directory does not exist, skipping cleanup", "temp-cleanup");
        return;
      }
      const now = Date.now();
      const files = await fs17.readdir(this.TEMP_DIR);
      let deletedCount = 0;
      let totalSize = 0;
      for (const file of files) {
        if (!file.startsWith("temp_report_")) {
          continue;
        }
        const filePath = path16.join(this.TEMP_DIR, file);
        try {
          const stats = await fs17.stat(filePath);
          const fileAge = now - stats.mtimeMs;
          if (fileAge > this.MAX_AGE_MS) {
            await fs17.unlink(filePath);
            deletedCount++;
            totalSize += stats.size;
            logger.debug(`Deleted old temp file: ${file} (age: ${Math.round(fileAge / 1e3 / 60)} minutes)`, "temp-cleanup");
          }
        } catch (error) {
          logger.warn(`Failed to process temp file: ${file}`, "temp-cleanup", error);
        }
      }
      if (deletedCount > 0) {
        const sizeMB = (totalSize / 1024 / 1024).toFixed(2);
        logger.info(`Cleanup completed: deleted ${deletedCount} files (${sizeMB} MB)`, "temp-cleanup");
      } else {
        logger.debug("Cleanup completed: no old files found", "temp-cleanup");
      }
    } catch (error) {
      logger.error("Temp file cleanup error", "temp-cleanup", error);
      throw error;
    }
  }
  /**
   * پاکسازی فوری تمام فایل‌های temp (استفاده در shutdown)
   */
  async cleanupAll() {
    try {
      logger.info("Cleaning up all temp files", "temp-cleanup");
      try {
        await fs17.access(this.TEMP_DIR);
      } catch {
        return;
      }
      const files = await fs17.readdir(this.TEMP_DIR);
      let deletedCount = 0;
      for (const file of files) {
        if (!file.startsWith("temp_report_")) {
          continue;
        }
        const filePath = path16.join(this.TEMP_DIR, file);
        try {
          await fs17.unlink(filePath);
          deletedCount++;
        } catch (error) {
          logger.warn(`Failed to delete temp file: ${file}`, "temp-cleanup", error);
        }
      }
      logger.info(`All temp files cleaned: ${deletedCount} files deleted`, "temp-cleanup");
    } catch (error) {
      logger.error("Cleanup all error", "temp-cleanup", error);
    }
  }
  /**
   * دریافت آمار فایل‌های موقت
   */
  async getStats() {
    try {
      await fs17.access(this.TEMP_DIR);
    } catch {
      return { totalFiles: 0, totalSize: 0, oldFiles: 0, oldSize: 0 };
    }
    const now = Date.now();
    const files = await fs17.readdir(this.TEMP_DIR);
    let totalFiles = 0;
    let totalSize = 0;
    let oldFiles = 0;
    let oldSize = 0;
    for (const file of files) {
      if (!file.startsWith("temp_report_")) {
        continue;
      }
      const filePath = path16.join(this.TEMP_DIR, file);
      try {
        const stats = await fs17.stat(filePath);
        totalFiles++;
        totalSize += stats.size;
        const fileAge = now - stats.mtimeMs;
        if (fileAge > this.MAX_AGE_MS) {
          oldFiles++;
          oldSize += stats.size;
        }
      } catch (error) {
      }
    }
    return { totalFiles, totalSize, oldFiles, oldSize };
  }
};
var tempFileCleanupService = new TempFileCleanupService();

